(window.webpackJsonp=window.webpackJsonp||[]).push([[574],{843:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for singly-linked list.\\n * function ListNode(val) {\\n *     this.val = val;\\n *     this.next = null;\\n * }\\n */</span>\\n\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{ListNode}</span> <span class=\\"hljs-variable\\">headA</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{ListNode}</span> <span class=\\"hljs-variable\\">headB</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{ListNode}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> getIntersectionNode = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">headA, headB</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(!headA || !headB)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">null</span>\\n  <span class=\\"hljs-keyword\\">let</span> nodeA=headA,nodeB=headB\\n  <span class=\\"hljs-keyword\\">while</span>(nodeA || nodeB){\\n    <span class=\\"hljs-keyword\\">if</span>(!nodeA)nodeA=headB\\n    <span class=\\"hljs-keyword\\">if</span>(!nodeB)nodeB=headA\\n    <span class=\\"hljs-keyword\\">if</span>(nodeA===nodeB)<span class=\\"hljs-keyword\\">return</span> nodeA\\n    nodeA=nodeA.next\\n    nodeB=nodeB.next\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">null</span>\\n};\\n</code></pre>\\n"],"titleSlug":"intersection-of-two-linked-lists","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u5047\u8bbe<code>node</code>\u4ece<code>headA</code>\u904d\u5386\u5b8c\u540e\u63a5\u7740\u4ece<code>headB</code>\u5f00\u59cb\uff0c<code>nodeB</code>\u4ece<code>headB</code>\u5230\u904d\u5386\u5b8c\u540e\u63a5\u7740\u4ece<code>headA</code>\u5f00\u59cb\uff0c\u90a3\u4e48\u6700\u540e\u8fd9\u4e24\u6761\u94fe\u8868\u662f\u7b49\u957f\u7684\uff0c\u5e76\u4e14\u6700\u7ec8\u4ed6\u4eec\u4f1a\u540c\u65f6\u5230\u8fbe\\n<code>headA==null &amp;&amp; headB==null</code>\u7684\u72b6\u6001\u3002</p>\\n<p>\u800c\u5728\u8fd9\u6bb5\u904d\u5386\u4e2d\uff0c\u5982\u679c\u5b58\u5728<code>nodeA===nodeB</code>\u7684\u60c5\u51b5\uff0c\u8bf4\u660e\u8fd9\u5c31\u662f\u5b83\u4eec\u7684\u76f8\u4ea4\u70b9\u3002</p>\\n<p>\u5426\u5219\u5219\u4e0d\u5b58\u5728\u76f8\u4ea4\u70b9\u3002</p>\\n","content":"<p>\u7ed9\u4f60\u4e24\u4e2a\u5355\u94fe\u8868\u7684\u5934\u8282\u70b9\xa0<code>headA</code> \u548c <code>headB</code> \uff0c\u8bf7\u4f60\u627e\u51fa\u5e76\u8fd4\u56de\u4e24\u4e2a\u5355\u94fe\u8868\u76f8\u4ea4\u7684\u8d77\u59cb\u8282\u70b9\u3002\u5982\u679c\u4e24\u4e2a\u94fe\u8868\u6ca1\u6709\u4ea4\u70b9\uff0c\u8fd4\u56de <code>null</code> \u3002</p>\\n\\n<p>\u56fe\u793a\u4e24\u4e2a\u94fe\u8868\u5728\u8282\u70b9 <code>c1</code> \u5f00\u59cb\u76f8\u4ea4<strong>\uff1a</strong></p>\\n\\n<p><a href=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2018/12/14/160_statement.png\\" target=\\"_blank\\"><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2018/12/14/160_statement.png\\" style=\\"height: 130px; width: 400px;\\" /></a></p>\\n\\n<p>\u9898\u76ee\u6570\u636e <strong>\u4fdd\u8bc1</strong> \u6574\u4e2a\u94fe\u5f0f\u7ed3\u6784\u4e2d\u4e0d\u5b58\u5728\u73af\u3002</p>\\n\\n<p><strong>\u6ce8\u610f</strong>\uff0c\u51fd\u6570\u8fd4\u56de\u7ed3\u679c\u540e\uff0c\u94fe\u8868\u5fc5\u987b <strong>\u4fdd\u6301\u5176\u539f\u59cb\u7ed3\u6784</strong> \u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><a href=\\"https://assets.leetcode.com/uploads/2018/12/13/160_example_1.png\\" target=\\"_blank\\"><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2018/12/14/160_example_1.png\\" style=\\"height: 130px; width: 400px;\\" /></a></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>intersectVal = 8, listA = [4,1,8,4,5], listB = [5,0,1,8,4,5], skipA = 2, skipB = 3\\n<strong>\u8f93\u51fa\uff1a</strong>Intersected at \'8\'\\n<strong>\u89e3\u91ca\uff1a</strong>\u76f8\u4ea4\u8282\u70b9\u7684\u503c\u4e3a 8 \uff08\u6ce8\u610f\uff0c\u5982\u679c\u4e24\u4e2a\u94fe\u8868\u76f8\u4ea4\u5219\u4e0d\u80fd\u4e3a 0\uff09\u3002\\n\u4ece\u5404\u81ea\u7684\u8868\u5934\u5f00\u59cb\u7b97\u8d77\uff0c\u94fe\u8868 A \u4e3a [4,1,8,4,5]\uff0c\u94fe\u8868 B \u4e3a [5,0,1,8,4,5]\u3002\\n\u5728 A \u4e2d\uff0c\u76f8\u4ea4\u8282\u70b9\u524d\u6709 2 \u4e2a\u8282\u70b9\uff1b\u5728 B \u4e2d\uff0c\u76f8\u4ea4\u8282\u70b9\u524d\u6709 3 \u4e2a\u8282\u70b9\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b\xa02\uff1a</strong></p>\\n\\n<p><a href=\\"https://assets.leetcode.com/uploads/2018/12/13/160_example_2.png\\" target=\\"_blank\\"><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2018/12/14/160_example_2.png\\" style=\\"height: 136px; width: 350px;\\" /></a></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>intersectVal\xa0= 2, listA = [0,9,1,2,4], listB = [3,2,4], skipA = 3, skipB = 1\\n<strong>\u8f93\u51fa\uff1a</strong>Intersected at \'2\'\\n<strong>\u89e3\u91ca\uff1a</strong>\u76f8\u4ea4\u8282\u70b9\u7684\u503c\u4e3a 2 \uff08\u6ce8\u610f\uff0c\u5982\u679c\u4e24\u4e2a\u94fe\u8868\u76f8\u4ea4\u5219\u4e0d\u80fd\u4e3a 0\uff09\u3002\\n\u4ece\u5404\u81ea\u7684\u8868\u5934\u5f00\u59cb\u7b97\u8d77\uff0c\u94fe\u8868 A \u4e3a [0,9,1,2,4]\uff0c\u94fe\u8868 B \u4e3a [3,2,4]\u3002\\n\u5728 A \u4e2d\uff0c\u76f8\u4ea4\u8282\u70b9\u524d\u6709 3 \u4e2a\u8282\u70b9\uff1b\u5728 B \u4e2d\uff0c\u76f8\u4ea4\u8282\u70b9\u524d\u6709 1 \u4e2a\u8282\u70b9\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b\xa03\uff1a</strong></p>\\n\\n<p><a href=\\"https://assets.leetcode.com/uploads/2018/12/13/160_example_3.png\\" target=\\"_blank\\"><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2018/12/14/160_example_3.png\\" style=\\"height: 126px; width: 200px;\\" /></a></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>intersectVal = 0, listA = [2,6,4], listB = [1,5], skipA = 3, skipB = 2\\n<strong>\u8f93\u51fa\uff1a</strong>null\\n<strong>\u89e3\u91ca\uff1a</strong>\u4ece\u5404\u81ea\u7684\u8868\u5934\u5f00\u59cb\u7b97\u8d77\uff0c\u94fe\u8868 A \u4e3a [2,6,4]\uff0c\u94fe\u8868 B \u4e3a [1,5]\u3002\\n\u7531\u4e8e\u8fd9\u4e24\u4e2a\u94fe\u8868\u4e0d\u76f8\u4ea4\uff0c\u6240\u4ee5 intersectVal \u5fc5\u987b\u4e3a 0\uff0c\u800c skipA \u548c skipB \u53ef\u4ee5\u662f\u4efb\u610f\u503c\u3002\\n\u8fd9\u4e24\u4e2a\u94fe\u8868\u4e0d\u76f8\u4ea4\uff0c\u56e0\u6b64\u8fd4\u56de null \u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>listA</code> \u4e2d\u8282\u70b9\u6570\u76ee\u4e3a <code>m</code></li>\\n\\t<li><code>listB</code> \u4e2d\u8282\u70b9\u6570\u76ee\u4e3a <code>n</code></li>\\n\\t<li><code>0 <= m, n <= 3 * 10<sup>4</sup></code></li>\\n\\t<li><code>1 <= Node.val <= 10<sup>5</sup></code></li>\\n\\t<li><code>0 <= skipA <= m</code></li>\\n\\t<li><code>0 <= skipB <= n</code></li>\\n\\t<li>\u5982\u679c <code>listA</code> \u548c <code>listB</code> \u6ca1\u6709\u4ea4\u70b9\uff0c<code>intersectVal</code> \u4e3a <code>0</code></li>\\n\\t<li>\u5982\u679c <code>listA</code> \u548c <code>listB</code> \u6709\u4ea4\u70b9\uff0c<code>intersectVal == listA[skipA + 1] == listB[skipB + 1]</code></li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u8fdb\u9636\uff1a</strong>\u4f60\u80fd\u5426\u8bbe\u8ba1\u4e00\u4e2a\u65f6\u95f4\u590d\u6742\u5ea6 <code>O(n)</code> \u3001\u4ec5\u7528 <code>O(1)</code> \u5185\u5b58\u7684\u89e3\u51b3\u65b9\u6848\uff1f</p>\\n","title":"160. \u76f8\u4ea4\u94fe\u8868","relatedTags":["\u94fe\u8868"],"difficult":"Easy","lang":["javascript"],"uniqueID":"160"}')}}]);